interface DashboardLayoutProps {
  grid: GridConfig;
  layout: WidgetLayout[];
  editable: boolean;
  renderWidget: (widget: WidgetLayout) => React.ReactNode;
  onLayoutCommit: (layout: WidgetLayout[], reason: 'drag' | 'resize' | 'keyboard' | 'reset') => void;
  onLayoutPreview?: (layout: WidgetLayout[]) => void; // optional, throttled or rAF-batched only
  onSaveStatusChange?: (status: 'idle' | 'saving' | 'saved' | 'failed') => void;
}

interface DashboardLayoutHandle {
  resetLayout(): void;
  focusWidget(id: string): void;
  moveWidgetByKeyboard(id: string, delta: { x: number; y: number }): void;
  resizeWidgetByKeyboard(id: string, delta: { width: number; height: number }): void;
}
